SELECT /*+ leading(PS) */ DDM.STB_ID ,DECODE(LENGTH(STB.USER_SERVICE_NUM),10,'상용','테스트용' ) STBDIVISION ,PS.MAC_ADDRESS ,(SELECT SM.MODEL_NAME FROM STB_MODEL SM WHERE SM.MODEL_CODE = PS.MODEL_CODE ) MODEL_NAME ,(SELECT MCM.CUG_NM FROM DM_CUG_MST DCM ,MN_CUG_MST MCM WHERE To_char(stb.service_code) = DCM.CUG_ID AND DCM.CUG_ID = MCM.CUG_ID AND ROWNUM = 1) CUG_EXPL ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'IPTV_STATUS_CODE' AND COMM.COMM_CD = STB.IPTV_STATUS_CODE ) CD_NM ,DDM.CLNT_IPADDR ,DDM.RCU_MANUFR_CD ,DDM.RCU_FIRM_VER ,DDM.CLNT_PUB_IPADDR ,DDM.STB_SW_VER STB_SW_PLAN_INST_VER ,DDM.STB_SW_PLAN_LAST_VER ,DDM.PLAN_ID ,UUPM.PLAN_NM ,TO_CHAR(DDM.STB_LAST_CONN_DATE, 'YYYY.MM.DD HH24:MI') STB_LAST_CONN_DATE ,TO_CHAR(DDM.STM_UPTM, 'YYYY.MM.DD HH24:MI') STM_UPTM ,DECODE(DDM.STM_UPTM,NULL,'',TRUNC(SYSDATE) - TRUNC(DDM.STM_UPTM)||'일') AS OVERUPTIME ,'N' AS MYSTBYN ,(SELECT DQTM.TEAM_NM FROM DM_QLTY_TEAM_MST DQTM WHERE DDM.TEAM_CD = DQTM.TEAM_CD AND ROWNUM = 1) AREAQLTY ,STB.USER_SERVICE_NUM ,DECODE(DDM.HDMI_POW,'1','사용함','0','사용 안함',NULL) HDMI_POW ,DECODE(DDM.RCU_PAIRING,'1','Y','0','N',NULL) RCU_PAIRING ,DDM.TEAM_CD
,TO_CHAR(DDM.STB_SW_UPD_DATE,'YYYY.MM.DD HH24:MI') STB_SW_UPD_DATE ,DDM.LOCK_YN ,DDM.UPD_YN ,DDM.native_ui_ver ,DDM.web_ui_ver ,SD.SCRBR_TYP_CD ,SD.TBR_SO_CL_CD ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'SCRBR_TYP_CD' AND COMM.COMM_CD = SD.SCRBR_TYP_CD ) SCRBR_TYP_NM ,DADM.ACC_SW_VER ,DADM.ACC_MODL_NM ,DDM.EXE_SCH_ID ,UPPESL.EXE_SCH_NM ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'UPD_STS_FG_CD' AND COMM.COMM_CD = UPPESL.UPD_STS_FG_CD AND ROWNUM = 1) UPD_STS_FG_CD_NM FROM STB STB ,DM_DVC_MST DDM ,PHYSICAL_STB PS ,UM_UPD_PLAN_MST UUPM ,STB_DTL SD ,DM_ACC_DVC_MST DADM ,UM_UPD_PLAN_EXE_SCH_LST UPPESL
,DM_DVC_GRP_MST GM ,DM_DVC_GRP_PSNL_MAP GPM
WHERE 1=1 AND DDM.STB_ID = STB.STB_ID AND DDM.STB_ID = PS.STB_ID (+) AND DDM.PLAN_ID = UUPM.PLAN_ID (+) AND DDM.STB_ID = SD.STB_ID (+) AND DDM.STB_ID = DADM.STB_ID (+) AND DDM.EXE_SCH_ID = UPPESL.EXE_SCH_ID (+)
AND GM.DVC_GRP_ID = GPM.DVC_GRP_ID(+) AND DDM.STB_ID = GPM.STB_ID AND GM.DVC_GRP_FG_CD = '02' AND UPPER(GM.DVC_GRP_NM) LIKE UPPER('%' || #{deviceGroup} || '%')
AND DDM.UPD_YN = #{searchUpdYn}
AND PS.MAC_ADDRESS = LOWER(#{macAddress})
AND ${otherCondition} = #{otherTxt}
AND STB.STB_ID = UPPER(#{stbId})
AND ${versionCondition} BETWEEN #{toVersion} AND #{fromVersion}
AND ${versionCondition} = #{toVersion}
AND ${versionCondition} >= #{toVersion}
AND ${versionCondition} <= #{toVersion}
AND DDM.TEAM_CD IN
#{type}
AND PS.MODEL_CODE IN
#{type}
AND TRIM(STB.SERVICE_CODE) IN
#{type}
AND STB.NETWORK_BRAND_CODE IN
#{type}
AND STB.IPTV_STATUS_CODE IN
#{type}
AND STB.ID_PACKAGE IN
#{type}
AND SD.SCRBR_TYP_CD IN
#{type}
AND DDM.STM_UPTM BETWEEN TO_DATE(#{fromUptm}||'00:00:00','yyyyMMdd HH24:MI:SS') AND TO_DATE(#{toUptm}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND DDM.STM_UPTM BETWEEN TO_DATE(#{fromUptm}||'00:00:00','yyyyMMdd HH24:MI:SS') AND TO_DATE(#{fromUptm}||'23:59:59','yyyyMMdd HH24:MI:SS')
AND DDM.STM_UPTM >= TO_DATE(#{fromUptm})
AND DDM.STM_UPTM <= TO_DATE(#{fromUptm})+0.99999
AND DDM.STM_UPTM BETWEEN TRUNC(SYSDATE-#{overTimeTo}) AND TRUNC(SYSDATE-#{overTimeFrom})+0.99999
AND DDM.STM_UPTM BETWEEN TRUNC(SYSDATE-#{overTime}) AND TRUNC(SYSDATE-#{overTime})+0.99999
AND DDM.STM_UPTM <= TRUNC(SYSDATE-#{overTime})+0.99999
AND DDM.STM_UPTM >= TRUNC(SYSDATE-#{overTime})
AND LENGTH(STB.USER_SERVICE_NUM) = 10
AND LENGTH(STB.USER_SERVICE_NUM) != 10
AND DDM.STB_ID IN (SELECT STB_ID FROM dm_acc_dvc_mst WHERE acc_modl_id = #{accModlId}
AND acc_sw_ver = #{accSwVer}
)
ORDER BY DDM.STB_ID
${endRow}
${startRow}

