SELECT DDM.STB_ID ,DECODE(LENGTH(STB.USER_SERVICE_NUM),10,'상용','테스트용' ) STBDIVISION ,PS.MAC_ADDRESS ,(SELECT SM.MODEL_NAME FROM STB_MODEL SM WHERE SM.MODEL_CODE = PS.MODEL_CODE ) MODEL_NAME ,(SELECT MCM.CUG_NM FROM DM_CUG_MST DCM ,MN_CUG_MST MCM WHERE To_char(stb.service_code) = DCM.CUG_ID AND DCM.CUG_ID = MCM.CUG_ID AND ROWNUM = 1) CUG_EXPL ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'IPTV_STATUS_CODE' AND COMM.COMM_CD = STB.IPTV_STATUS_CODE ) CD_NM ,DDM.CLNT_IPADDR ,DDM.RCU_MANUFR_CD ,DDM.RCU_FIRM_VER ,DDM.CLNT_PUB_IPADDR ,DDM.STB_SW_VER STB_SW_PLAN_INST_VER ,DDM.STB_SW_PLAN_LAST_VER ,DDM.PLAN_ID ,UUPM.PLAN_NM ,TO_CHAR(DDM.STB_LAST_CONN_DATE, 'YYYY.MM.DD HH24:MI') STB_LAST_CONN_DATE ,TO_CHAR(DDM.STM_UPTM, 'YYYY.MM.DD HH24:MI') STM_UPTM ,DECODE(DDM.STM_UPTM,NULL,'',TRUNC(SYSDATE) - TRUNC(DDM.STM_UPTM)||'일') AS OVERUPTIME ,'N' AS MYSTBYN ,(SELECT DQTM.TEAM_NM FROM DM_QLTY_TEAM_MST DQTM WHERE DDM.TEAM_CD = DQTM.TEAM_CD AND ROWNUM = 1) AREAQLTY ,STB.USER_SERVICE_NUM ,DECODE(DDM.HDMI_POW,'1','사용함','0','사용 안함',NULL) HDMI_POW ,DECODE(DDM.RCU_PAIRING,'1','Y','0','N',NULL) RCU_PAIRING ,DDM.TEAM_CD ,TO_CHAR(DDM.STB_SW_UPD_DATE,'YYYY.MM.DD HH24:MI') STB_SW_UPD_DATE ,DDM.LOCK_YN ,DDM.UPD_YN ,DDM.native_ui_ver ,DDM.web_ui_ver ,SD.SCRBR_TYP_CD ,SD.TBR_SO_CL_CD ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'SCRBR_TYP_CD' AND COMM.COMM_CD = SD.SCRBR_TYP_CD ) SCRBR_TYP_NM ,DADM.ACC_SW_VER ,DADM.ACC_MODL_NM ,DDM.EXE_SCH_ID ,UPPESL.EXE_SCH_NM ,(SELECT COMM.CD_NM FROM AD_COMM_CD COMM WHERE COMM.COMM_GRP_CD = 'UPD_STS_FG_CD' AND COMM.COMM_CD = UPPESL.UPD_STS_FG_CD AND ROWNUM = 1) UPD_STS_FG_CD_NM FROM DM_DVC_MST DDM ,STB STB ,PHYSICAL_STB PS ,UM_UPD_PLAN_MST UUPM ,STB_DTL SD ,DM_ACC_DVC_MST DADM ,UM_UPD_PLAN_EXE_SCH_LST UPPESL WHERE 1=1 AND DDM.STB_ID = STB.STB_ID AND DDM.STB_ID = PS.STB_ID (+) AND DDM.PLAN_ID = UUPM.PLAN_ID (+) AND DDM.STB_ID = SD.STB_ID (+) AND DDM.STB_ID = DADM.STB_ID (+) AND DDM.EXE_SCH_ID = UPPESL.EXE_SCH_ID (+)
AND ${searchType} IN
UPPER(#{type})
LOWER(#{type})
${endRow}
${startRow}

SELECT sts_f.PLAN_ID , sts_f.EXE_SCH_ID , (SELECT plan_nm FROM UM_UPD_PLAN_MST planMst WHERE planMst.PLAN_ID = sts_f.PLAN_ID) PLAN_NM , sts_f.MAC_ADDR , sts_f.MODL_NM , sts_f.STB_SW_VER , sts_l.STB_SW_PLAN_LAST_VER , sts_l.STB_SW_PLAN_INST_VER , sts_f.STM_FIR_REG_DATE -- 마스터에 처에 쌓인 row의 등록 일시 , sts_l.STM_LAST_UPD_DATE , err.PRG_STS_FG_CD , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = err.PRG_STS_FG_CD AND COMM_GRP_CD = 'PRG_STS_FG_CD') PRG_STS_FG_NM , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = sts_l.CUST_NOTY_MT_FG_CD AND COMM_GRP_CD = 'CUST_NOTY_MT_FG_CD' ) CUST_NOTY_MT_FG_CD FROM UM_UPD_PLAN_STS_MST sts_f ,UM_UPD_PLAN_STS_MST sts_l , ( SELECT A.EXE_SCH_ID , MIN(A.STM_FIR_REG_DATE) AS STM_FIR_REG_DATE , MAX(A.STM_FIR_REG_DATE) AS STM_LAST_UPD_DATE FROM UM_UPD_PLAN_STS_MST A , UM_ERR_CD_MST B WHERE A.ERR_CD = B.ERR_CD AND A.STB_ID = UPPER(#{stbId}) GROUP BY A.EXE_SCH_ID ) mst , UM_ERR_CD_MST err WHERE sts_l.ERR_CD = err.ERR_CD AND sts_f.STB_ID = UPPER(#{stbId}) AND sts_l.STB_ID = UPPER(#{stbId}) AND sts_f.EXE_SCH_ID = mst.EXE_SCH_ID AND sts_f.STM_FIR_REG_DATE = mst.STM_FIR_REG_DATE AND sts_l.EXE_SCH_ID = mst.EXE_SCH_ID AND sts_l.STM_FIR_REG_DATE = mst.STM_LAST_UPD_DATE
AND err.PRG_STS_FG_CD = #{state}
ORDER BY sts_l.STM_LAST_UPD_DATE DESC

SELECT * FROM (
SELECT '01' DVC_FG_CD , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = '01' AND COMM_GRP_CD = 'DVC_FG_CD') DVC_FG_NM , sts_f.PLAN_ID , sts_f.EXE_SCH_ID , (SELECT plan_nm FROM UM_UPD_PLAN_MST planMst WHERE planMst.PLAN_ID = sts_f.PLAN_ID) PLAN_NM , sts_f.MAC_ADDR , sts_f.MODL_NM , sts_f.STB_SW_VER , sts_l.STB_SW_PLAN_LAST_VER , sts_l.STB_SW_PLAN_INST_VER , sts_f.STM_FIR_REG_DATE , sts_l.STM_LAST_UPD_DATE , err.PRG_STS_FG_CD , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = err.PRG_STS_FG_CD AND COMM_GRP_CD = 'PRG_STS_FG_CD') PRG_STS_FG_NM , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = sts_l.CUST_NOTY_MT_FG_CD AND COMM_GRP_CD = 'CUST_NOTY_MT_FG_CD' ) CUST_NOTY_MT_FG_CD FROM UM_UPD_PLAN_STS_MST sts_f , UM_UPD_PLAN_STS_MST sts_l , ( SELECT A.PLAN_ID, A.EXE_SCH_ID, A.STB_ID , MIN(A.STM_FIR_REG_DATE) AS STM_FIR_REG_DATE , MAX(A.STM_FIR_REG_DATE) AS STM_LAST_UPD_DATE FROM UM_UPD_PLAN_STS_MST A WHERE 1=1 AND A.STB_ID = UPPER(#{stbId}) GROUP BY A.PLAN_ID, A.EXE_SCH_ID, A.STB_ID ) mst , UM_ERR_CD_MST err WHERE sts_l.ERR_CD = err.ERR_CD AND sts_f.STB_ID = mst.STB_ID AND sts_l.STB_ID = mst.STB_ID AND sts_f.EXE_SCH_ID = mst.EXE_SCH_ID AND sts_f.STM_FIR_REG_DATE = mst.STM_FIR_REG_DATE AND sts_l.EXE_SCH_ID = mst.EXE_SCH_ID AND sts_l.STM_FIR_REG_DATE = mst.STM_LAST_UPD_DATE AND err.PRG_STS_FG_CD = #{state}
UNION ALL
SELECT '02' DVC_FG_CD , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = '02' AND COMM_GRP_CD = 'DVC_FG_CD') DVC_FG_NM , al.ACC_DISTB_ID PLAN_ID , al.ACC_TRANS_ID EXE_SCH_ID , al.ACC_DISTB_ID PLAN_NM , al.ACC_MAC_ADDR MAC_ADDR , al.ACC_MODL_NM MODL_NM , al.ACC_SW_VER STB_SW_VER , al.ACC_SW_DISTB_LAST_VER STB_SW_PLAN_LAST_VER , al.ACC_SW_DISTB_INST_VER STB_SW_PLAN_INST_VER , af.STM_FIR_REG_DATE STM_FIR_REG_DATE , al.STM_FIR_REG_DATE STM_LAST_UPD_DATE , err.PRG_STS_FG_CD , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = err.PRG_STS_FG_CD AND COMM_GRP_CD = 'PRG_STS_FG_CD') PRG_STS_FG_NM , (SELECT CD_NM FROM AD_COMM_CD cd WHERE cd.COMM_CD = m.UPD_MT_FG_CD AND COMM_GRP_CD = 'ACC_UPD_MT_FG_CD' ) CUST_NOTY_MT_FG_CD FROM UM_UPD_ACC_DISTB_MST m, UM_UPD_ACC_DISTB_STS_HST af, UM_UPD_ACC_DISTB_STS_HST al, UM_ERR_CD_MST err , ( SELECT ACC_DISTB_ID, ACC_TRANS_ID, STB_ID, MIN(stm_fir_reg_date) MIN_DATE, MAX(stm_fir_reg_date) MAX_DATE FROM UM_UPD_ACC_DISTB_STS_HST WHERE 1=1 AND STB_ID = UPPER(#{stbId}) GROUP BY ACC_DISTB_ID, ACC_TRANS_ID, STB_ID ) g WHERE 1=1 AND g.ACC_DISTB_ID = al.ACC_DISTB_ID AND g.ACC_TRANS_ID = al.ACC_TRANS_ID AND g.MAX_DATE = al.STM_FIR_REG_DATE AND g.STB_ID = al.STB_ID AND g.ACC_DISTB_ID = af.ACC_DISTB_ID AND g.ACC_TRANS_ID = af.ACC_TRANS_ID AND g.MIN_DATE = af.STM_FIR_REG_DATE AND g.STB_ID = af.STB_ID AND al.ACC_DISTB_ID = m.ACC_DISTB_ID AND al.ERR_CD = err.ERR_CD AND err.PRG_STS_FG_CD = #{state}
) ORDER BY STM_LAST_UPD_DATE DESC

-- RCU 상태 이력 SELECT a.STM_FIR_REG_DATE , a.ACC_TRANS_ID exe_sch_id , a.ACC_SW_DISTB_INST_VER STB_SW_PLAN_INST_VER , a.ERR_CD , err.ERR_NM , err.ERR_EXPL , err.PRG_STS_FG_CD , (SELECT CD_NM FROM AD_COMM_CD CD WHERE err.PRG_STS_FG_CD = CD.COMM_CD AND COMM_GRP_CD = 'PRG_STS_FG_CD') PRG_STS_FG_Nm FROM UM_UPD_ACC_DISTB_STS_HST a, UM_ERR_CD_MST err WHERE 1=1 AND a.STB_ID = UPPER(#{stbId}) AND a.ACC_DISTB_ID = #{planId}
AND a.ACC_TRANS_ID = #{exeSchId}
AND a.ERR_CD = err.ERR_CD ORDER BY STM_FIR_REG_DATE DESC, PRG_STS_FG_CD DESC

