SELECT A.PLAN_ID, A.EXE_SCH_ID, A.STB_ID, A.MAC_ADDR, A.LAST_STB_SW_VER, A.LAST_STB_SW_PLAN_LAST_VER, A.LAST_ERR_CD, A.LAST_CUST_NOTY_MT_FG_CD, A.LAST_STM_LAST_UPD_USER_ID, A.LAST_STM_LAST_UPD_DATE, A.LAST_ERR_OCCR_DATE, DDM.UPD_YN UPD_YN, STB.USER_SERVICE_NUM USER_SERVICE_NUM, NVL( ( SELECT USER_NM FROM AD_USER_MST WHERE USER_ID = A.LAST_STM_LAST_UPD_USER_ID ), A.LAST_STM_LAST_UPD_USER_ID ) AS LAST_STM_LAST_UPD_USER_NM, DECODE(LENGTH(STB.USER_SERVICE_NUM), 10, '상용', '테스트용') AS STB_DIVISION, CUST_COMM_CD.CD_NM AS LAST_CUST_NOTY_MT_FG_CD_NM, UECM.ERR_NM AS LAST_ERR_CD_NM, A.SCH_ERR_CNT -- 맨마지막 FROM ( SELECT PLAN_ID, EXE_SCH_ID, STB_ID, MAC_ADDR, STB_SW_VER AS LAST_STB_SW_VER, STB_SW_PLAN_LAST_VER AS LAST_STB_SW_PLAN_LAST_VER, ERR_CD AS LAST_ERR_CD, CUST_NOTY_MT_FG_CD AS LAST_CUST_NOTY_MT_FG_CD, STM_LAST_UPD_USER_ID AS LAST_STM_LAST_UPD_USER_ID, STM_LAST_UPD_DATE AS LAST_STM_LAST_UPD_DATE, ERR_OCCR_DATE AS LAST_ERR_OCCR_DATE, ERR_CNT AS SCH_ERR_CNT FROM ( SELECT PLAN_ID, EXE_SCH_ID, STB_ID, MAC_ADDR, STB_SW_VER, STB_SW_PLAN_LAST_VER, ERR_CD, CUST_NOTY_MT_FG_CD, STM_LAST_UPD_USER_ID, STM_LAST_UPD_DATE, ERR_OCCR_DATE, -- 오류 발생횟수 COUNT(*) OVER ( PARTITION BY PLAN_ID, EXE_SCH_ID, STB_ID, MAC_ADDR, ERR_CD ) AS ERR_CNT, ROW_NUMBER() OVER ( PARTITION BY PLAN_ID, EXE_SCH_ID, STB_ID, MAC_ADDR ORDER BY STM_LAST_UPD_DATE DESC ) AS RN FROM UM_UPD_PLAN_ERR_MST WHERE EXE_SCH_ID = #{schExeSchId} AND EXISTS ( SELECT 1 FROM ( SELECT PLAN_ID, EXE_SCH_ID, STB_ID, MAC_ADDR, ERR_CD FROM UM_UPD_PLAN_ERR_MST WHERE EXE_SCH_ID = #{schExeSchId} GROUP BY PLAN_ID, EXE_SCH_ID, STB_ID, MAC_ADDR, ERR_CD
HAVING COUNT(*) >= #{schErrCnt}
) SUB WHERE 1=1 AND SUB.PLAN_ID = UM_UPD_PLAN_ERR_MST.PLAN_ID AND SUB.STB_ID = UM_UPD_PLAN_ERR_MST.STB_ID AND SUB.MAC_ADDR = UM_UPD_PLAN_ERR_MST.MAC_ADDR GROUP BY SUB.PLAN_ID, SUB.EXE_SCH_ID, SUB.STB_ID, SUB.MAC_ADDR ) ) C WHERE RN = 1 ) A JOIN DM_DVC_MST DDM ON A.STB_ID = DDM.STB_ID AND DDM.ERR_CD != #{schExcludeCd} JOIN STB STB ON A.STB_ID = STB.STB_ID LEFT OUTER JOIN AD_COMM_CD CUST_COMM_CD ON CUST_COMM_CD.COMM_GRP_CD = 'CUST_NOTY_MT_FG_CD' AND A.LAST_CUST_NOTY_MT_FG_CD = CUST_COMM_CD.COMM_CD LEFT OUTER JOIN UM_ERR_CD_MST UECM ON A.LAST_ERR_CD = UECM.ERR_CD ORDER BY A.LAST_STM_LAST_UPD_DATE DESC
